module RefModule(
  input clk,
  input rst,
  input in,
  output reg out  // Change from wire to reg to hold the output unused_state
);// Define the states
  parameter State1 = 2'b00;
  parameter State2 = 2'b01;
  parameter State3 = 2'b10;

  // Define the unused_state register and next unused_state logic
  reg [1:0] unused_state, next_state;

  always @(posedge clk, posedge rst) begin
    if (rst) begin
      unused_state <= State1;
    end else begin
      unused_state <= next_state;
    end
  end

  // Define the output function
  always @(unused_state, in) begin
    case(unused_state)
      State1: out = 1'b0;
      State2: out = 1'b1;
      State3: out = 1'b1;
      default: out = 1'b0; // Add a default case for safety
    endcase
  end

  // Define the next unused_state logic
  always @(unused_state, in) begin
    case(unused_state)
      State1: if (in) begin
                next_state = State2;
              end else begin
                next_state = State1;
              end
      State2: if (!in) begin
                next_state = State3;
              end else begin
                next_state = State2;
              end
      State3: if (in) begin
                next_state = State1;
              end else begin
                next_state = State3;
              end
      default: next_state = State1; // Add a default case for safety
    endcase
  end

endmodule
